import React from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import ZapatillasList from './components/ZapatillasList';
import AddZapatilla from './components/AddZapatilla';

const App = () => {
  return (
    <Router>
      <div className="min-h-screen bg-gray-100">
        <header className="bg-blue-500 text-white p-4">
          <h1 className="text-3xl">Catalogo de Zapatillas</h1>
        </header>
        <Routes>
          <Route path="/" element={<ZapatillasList />} />
          <Route path="/add" element={<AddZapatilla />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
